import React, { useEffect, useState } from 'react';
import { useNavigate, useParams, Link } from 'react-router-dom';
import { createArtiste, getArtiste, updateArtiste } from '../api/artisteService';

export default function ArtisteForm() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [model, setModel] = useState({ nom: '', description: '', image: null });
  const [existingImage, setExistingImage] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (id) {
      setLoading(true);
      getArtiste(id)
        .then((response) => {
          setModel({
            nom: response.data.nom || '',
            description: response.data.description || '',
            image: null,
          });
          setExistingImage(response.data.image || '');
        })
        .finally(() => setLoading(false));
    }
  }, [id]);

  const handleSubmit = (e) => {
    e.preventDefault();
    setLoading(true);

    const payload = {
      nom: model.nom,
      description: model.description,
      image: existingImage,
    };

    const op = id ? updateArtiste(id, payload) : createArtiste(payload);
    op.then(() => navigate('/artistes')).finally(() => setLoading(false));
  };

  return (
    <div>
      <div className="d-flex align-items-center justify-content-between mb-4">
        <div>
          <h1 className="h3 mb-0">{id ? 'Modifier' : 'Créer'} un artiste</h1>
          <p className="text-muted mb-0">Tous les champs ci-dessous seront stockés dans la bibliothèque d'artistes.</p>
        </div>
        <Link className="btn btn-secondary" to="/artistes">
          Retour aux artistes
        </Link>
      </div>

      <form onSubmit={handleSubmit} className="card shadow-sm border-0 p-4">
        <div className="mb-3">
          <label className="form-label">Nom de l'artiste</label>
          <input
            type="text"
            className="form-control"
            value={model.nom}
            onChange={(e) => setModel({ ...model, nom: e.target.value })}
            required
          />
        </div>

        <div className="mb-3">
          <label className="form-label">Description</label>
          <textarea
            className="form-control"
            rows="4"
            value={model.description}
            onChange={(e) => setModel({ ...model, description: e.target.value })}
          />
        </div>

        {existingImage && (
          <div className="mb-3">
            <label className="form-label">Image actuelle</label>
            <div>
              <img
                src={`/uploads/images/${existingImage}`}
                alt={model.nom}
                className="img-thumbnail"
                style={{ maxWidth: 180 }}
              />
            </div>
          </div>
        )}

        <div className="mb-4">
          <label className="form-label">Image (nom de fichier ou URL relative)</label>
          <input
            type="text"
            className="form-control"
            value={existingImage}
            onChange={(e) => setExistingImage(e.target.value)}
            placeholder="Ex: artiste-photo.jpg"
          />
          <div className="form-text">Saisissez le nom de fichier existant ou laissez vide.</div>
        </div>

        <button className="btn btn-primary" type="submit" disabled={loading}>
          {loading ? 'Enregistrement...' : 'Sauvegarder'}
        </button>
      </form>
    </div>
  );
}
